/**
 * DELETE /api/ao/quotes/purge-v1-cards
 *
 * One-time cleanup: deletes all scheduled quote cards generated by
 * the V1 Auto system that have not yet published.
 *
 * Targets ONLY rows where:
 *   - status = 'scheduled'
 *   - source_kind = 'auto_pull_quote_card'
 *   - created_by_email = owner email
 *
 * Nothing else in ao_scheduled_posts is touched.
 * Requires owner session. POST only.
 */

import { requireAoSession } from '../../../lib/ao/requireAoSession.js';
import { supabaseAdmin } from '../../../lib/supabase-admin.js';

export default async function handler(req, res) {
  const auth = requireAoSession(req, res);
  if (!auth) return;

  if (req.method !== 'POST') {
    return res.status(405).json({ ok: false, error: 'Method not allowed' });
  }

  try {
    // First: count what we're about to delete so we can report it
    const { count, error: countErr } = await supabaseAdmin
      .from('ao_scheduled_posts')
      .select('*', { count: 'exact', head: true })
      .eq('status', 'scheduled')
      .eq('source_kind', 'auto_pull_quote_card')
      .eq('intent->>created_by_email', auth.email);

    if (countErr) {
      return res.status(500).json({ ok: false, error: countErr.message });
    }

    // Execute the delete
    const { error: deleteErr } = await supabaseAdmin
      .from('ao_scheduled_posts')
      .delete()
      .eq('status', 'scheduled')
      .eq('source_kind', 'auto_pull_quote_card')
      .eq('intent->>created_by_email', auth.email);

    if (deleteErr) {
      return res.status(500).json({ ok: false, error: deleteErr.message });
    }

    return res.status(200).json({
      ok: true,
      deleted: count || 0,
      message: `Deleted ${count || 0} scheduled V1 quote card rows.`,
    });

  } catch (err) {
    console.error('[purge-v1-cards]', err?.message || err);
    return res.status(500).json({ ok: false, error: err?.message || 'Server error' });
  }
}
